The following examples demonstrate how to retrieve a breakdown of the
score using the [$search](pipe.$search) `scoreDetails` option for the
documents in the results for the [function expression example](function-score-egs) queries against the `sample_mflix.movies`
collection.**Arithmetic:**Arithmetic**Input:**```json
db.movies.aggregate([{
  "$search": {
    "text": {
      "path": "title",
      "query": "men",
      "score": {
        "function":{
          "multiply":[
            {
              "path": {
                "value": "imdb.rating",
                "undefined": 2
              }
            },
            {
              "score": "relevance"
            }
          ]
        }
      }
    },
    "scoreDetails": true
  }
},
{
  $limit: 5
},
{
  $project: {
    "_id": 0,
    "title": 1,
    "score": { "$meta": "searchScore" },
    "scoreDetails": {"$meta": "searchScoreDetails"}
  }
}])
